sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {
    var body = request.body.data;

    if (!body.requirement) {
        response.setStatus(400);
        response.setError('Requirement is required');
        return;
    }

    var options = {
        qualityWeight: body.qualityWeight || 0.5,
        tokenCostWeight: body.tokenCostWeight || 0.3,
        speedWeight: body.speedWeight || 0.2
    };

    var selector = new x_146833_idpkiro.BuildAgentSelector();
    var result = selector.selectAgent(body.requirement, options);

    if (result.error) {
        response.setStatus(400);
        response.setError(result.error);
        return;
    }

    response.setStatus(200);
    response.setBody({
        success: true,
        result: {
            agent: {
                sys_id: result.selectedAgent.sys_id,
                agent_id: result.selectedAgent.agent_id,
                name: result.selectedAgent.name,
                provider: result.selectedAgent.provider,
                model: result.selectedAgent.model,
                context_window: result.selectedAgent.context_window
            },
            score: result.score,
            reasoning: result.reasoning,
            allScores: result.allScores
        }
    });
})(request, response);
